mapper.select:
SELECT i.IMAGE_ID, i.SERVICE_ID, i.GENDER, i.IMAGE_URL, i.IMAGE_ALT, i.IS_ACTIVE, i.SORT_ORDER FROM mg_style_images i JOIN mg_services s ON i.SERVICE_ID = s.SERVICE_ID WHERE i.IS_ACTIVE = 1
AND i.GENDER = #{gender}
AND s.SERVICE_CODE = #{serviceCode}
ORDER BY i.SERVICE_ID ASC, i.SORT_ORDER ASC
